//! parity-cobordism-merge — embedding-only parity: single-station vs Frobenius
//! sum of 8 cobordism vocabulary shards.
//!
//! HYPOTHESIS UNDER TEST
//! ---------------------
//! The cobordism workers each call `embed_chunk_range(tokens, 0, vstart, vend)`
//! and the coordinator (Pipeline.ts) sums the 8 partial embeddings elementwise
//! (Frobenius merge μ: A ⊗ A → A) to reconstruct the full token-embedding row.
//!
//! Claim from the kernel docs: "Because token ranges are disjoint, exactly one
//! shard contributes a non-zero vector per token, making the merge equivalent
//! to identity." If this is wrong (e.g., off-by-one in the range checks, or
//! the underlying Q4_K dequant differs across calls), the wrong embedding
//! feeds the entire forward pipeline, producing weak/flat logits at the end.
//!
//! THE BIG QUESTION
//! ----------------
//! Does `embed_chunk(tokens)` bit-match `Σ embed_chunk_range(tokens, vs_i, ve_i)`
//! over the 8 worker-cobordism shards?
//!
//!   Path A (reference): pipeline.embed_chunk(tokens, 0)
//!   Path B (cobordism): for each shard i:
//!                          partial_i = pipeline.embed_chunk_range(tokens, 0, vs_i, ve_i)
//!                       sum_B = Σ partial_i (elementwise)
//!
//! Bit-perfect (cos = 1.0, max-abs = 0.0) means cobordism merge is innocent;
//! anything off means the embedding feed itself is broken.
//!
//! Edge cases also tested:
//!   - token = vocab_start of a shard       (inclusive boundary)
//!   - token = vocab_end - 1 of a shard     (last index in shard)
//!   - token outside any shard              (should be all-zero from every shard)
//!
//! Usage:
//!   cargo run --release --bin parity-cobordism-merge -- /tmp/qwen-coder-7b.knot

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

// Shard ranges from apps/worker-cobordism/aeon.toml
const SHARDS: [(usize, usize); 8] = [
    (0, 18992),
    (18992, 37984),
    (37984, 56976),
    (56976, 75968),
    (75968, 94960),
    (94960, 113952),
    (113952, 132944),
    (132944, 152064),
];

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0f64;
    let mut na = 0.0f64;
    let mut nb = 0.0f64;
    for i in 0..a.len() {
        let av = a[i] as f64;
        let bv = b[i] as f64;
        dot += av * bv;
        na += av * av;
        nb += bv * bv;
    }
    let denom = na.sqrt() * nb.sqrt();
    if denom == 0.0 {
        return 0.0;
    }
    (dot / denom) as f32
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut m = 0.0f32;
    for i in 0..a.len() {
        let d = (a[i] - b[i]).abs();
        if d > m {
            m = d;
        }
    }
    m
}

fn mean_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut s = 0.0f64;
    for i in 0..a.len() {
        s += (a[i] - b[i]).abs() as f64;
    }
    (s / a.len() as f64) as f32
}

fn frobenius_sum(partials: &[Vec<f32>]) -> Vec<f32> {
    let n = partials[0].len();
    let mut out = vec![0.0f32; n];
    for p in partials {
        debug_assert_eq!(p.len(), n);
        for i in 0..n {
            out[i] += p[i];
        }
    }
    out
}

fn count_nonzero(v: &[f32]) -> usize {
    v.iter().filter(|&&x| x != 0.0).count()
}

fn finite_stats(name: &str, v: &[f32]) {
    let mut nan = 0usize;
    let mut inf = 0usize;
    let mut lo = f32::INFINITY;
    let mut hi = f32::NEG_INFINITY;
    let mut sum = 0.0f64;
    for &x in v {
        if x.is_nan() {
            nan += 1;
            continue;
        }
        if x.is_infinite() {
            inf += 1;
            continue;
        }
        if x < lo {
            lo = x;
        }
        if x > hi {
            hi = x;
        }
        sum += x as f64;
    }
    let mean = sum / v.len() as f64;
    println!(
        "       [{}] len={} nan={} inf={} range=[{:.6}, {:.6}] mean={:.6}",
        name,
        v.len(),
        nan,
        inf,
        lo,
        hi,
        mean
    );
}

/// Owning shard for a token id (the unique i for which vs_i <= tid < ve_i).
fn owning_shard(tid: u32) -> Option<usize> {
    let t = tid as usize;
    for (i, (vs, ve)) in SHARDS.iter().enumerate() {
        if t >= *vs && t < *ve {
            return Some(i);
        }
    }
    None
}

/// Compare A vs B per-token; return (any_fail, max_global_max_abs).
fn compare_per_token(
    label: &str,
    tokens: &[u32],
    a: &[f32],
    b: &[f32],
    hidden_dim: usize,
) -> (bool, f32) {
    assert_eq!(a.len(), b.len(), "[{}] A/B length mismatch", label);
    assert_eq!(a.len(), tokens.len() * hidden_dim);
    let cos_all = cosine(a, b);
    let mxa_all = max_abs_delta(a, b);
    let mna_all = mean_abs_delta(a, b);
    println!(
        "  [{}] AGGREGATE  cos={:.10}  max-abs={:.10}  mean-abs={:.10}",
        label, cos_all, mxa_all, mna_all
    );
    let mut any_fail = false;
    let mut global_max = mxa_all;
    for (t, &tid) in tokens.iter().enumerate() {
        let ta = &a[t * hidden_dim..(t + 1) * hidden_dim];
        let tb = &b[t * hidden_dim..(t + 1) * hidden_dim];
        let c = cosine(ta, tb);
        let mx = max_abs_delta(ta, tb);
        let mn = mean_abs_delta(ta, tb);
        let owner = owning_shard(tid)
            .map(|i| format!("shard{}", i))
            .unwrap_or_else(|| "NONE".to_string());
        let pass = mx == 0.0;
        if !pass {
            any_fail = true;
        }
        if mx > global_max {
            global_max = mx;
        }
        println!(
            "    tok[{}]={:>6} ({})  cos={:.10}  max-abs={:.10}  mean-abs={:.10}  {}",
            t,
            tid,
            owner,
            c,
            mx,
            mn,
            if pass { "PASS" } else { "FAIL" }
        );
    }
    (any_fail, global_max)
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err(format!(
            "usage: {} <knot.path>",
            args.first()
                .map(String::as_str)
                .unwrap_or("parity-cobordism-merge")
        ));
    }
    let knot_path = args[1].clone();

    println!("============================================================");
    println!(" parity-cobordism-merge");
    println!("   knot   : {}", knot_path);
    println!("   shards : {} ranges over [0, 151936)", SHARDS.len());
    println!("============================================================");

    let knot = KnotWeights::load(&knot_path)?;
    let cfg = knot.config.as_ref().ok_or("no config block in knot")?;
    let hidden_dim = cfg.hidden_dim;
    let vocab_size = cfg.vocab_size;
    println!(
        "[meta] hidden={} layers={} vocab={} embed_qtype=will-be-discovered",
        cfg.hidden_dim, cfg.num_layers, cfg.vocab_size
    );
    // Sanity: shards cover [0, vocab_size) without gap or overlap.
    // FINDING: as of 2026-04-26, qwen-coder-7b config reports vocab_size=152064
    // but apps/worker-cobordism/aeon.toml stops at 151936 (HF nominal vocab).
    // The 128-token gap [151936, 152064) is uncovered by ANY shard — every
    // partial returns zero and the Frobenius merge produces a zero embedding
    // for those tokens. This is a real correctness bug for the cobordism path.
    let mut shard_cover_ok = true;
    if SHARDS[0].0 != 0 {
        println!(
            "[meta] shard cover: shard 0 does not start at 0 ({})",
            SHARDS[0].0
        );
        shard_cover_ok = false;
    }
    for i in 1..SHARDS.len() {
        if SHARDS[i].0 != SHARDS[i - 1].1 {
            println!(
                "[meta] shard cover: contiguity break between shard {} and {} ({} != {})",
                i - 1,
                i,
                SHARDS[i - 1].1,
                SHARDS[i].0
            );
            shard_cover_ok = false;
        }
    }
    let last_end = SHARDS[7].1;
    if last_end != vocab_size {
        println!(
            "[meta] !! GAP !! shard cover ends at {} but knot vocab_size={} — {} tokens uncovered [{}, {})",
            last_end, vocab_size, vocab_size - last_end, last_end, vocab_size
        );
        shard_cover_ok = false;
    }
    if shard_cover_ok {
        println!("[meta] shard cover: contiguous and exact OK");
    }

    // Single pipeline shared by both paths — same KV cache untouched, since
    // embed_* don't touch attention state. Embedding lookup is stateless w.r.t.
    // pipeline.pos.
    let mut p = NativeLlamaPipeline::from_knot(knot, false, 0.0);

    // ========================================================================
    // TEST 1 — main parity test, 4 hand-picked tokens spanning multiple shards
    // ========================================================================
    println!("\n----- TEST 1: 4 tokens spanning shards 0, 1, 2, 6 -----");
    // 100 -> shard 0, 20000 -> shard 1, 50000 -> shard 2, 130000 -> shard 6
    let tokens: Vec<u32> = vec![100, 20000, 50000, 130000];
    println!(
        "  tokens: {:?}  owners: [{}, {}, {}, {}]",
        tokens,
        owning_shard(tokens[0])
            .map(|i| format!("shard{}", i))
            .unwrap_or("NONE".into()),
        owning_shard(tokens[1])
            .map(|i| format!("shard{}", i))
            .unwrap_or("NONE".into()),
        owning_shard(tokens[2])
            .map(|i| format!("shard{}", i))
            .unwrap_or("NONE".into()),
        owning_shard(tokens[3])
            .map(|i| format!("shard{}", i))
            .unwrap_or("NONE".into()),
    );

    let t = Instant::now();
    let a = p.embed_chunk(&tokens, 0)?;
    println!(
        "[A] embed_chunk(seq_len=4) ok in {} ms  out={}",
        t.elapsed().as_millis(),
        a.len()
    );
    finite_stats("A", &a);

    let t = Instant::now();
    let mut partials: Vec<Vec<f32>> = Vec::with_capacity(SHARDS.len());
    for (i, (vs, ve)) in SHARDS.iter().enumerate() {
        let part = p.embed_chunk_range(&tokens, 0, *vs, *ve)?;
        let nz_per_token: Vec<usize> = (0..tokens.len())
            .map(|t_| count_nonzero(&part[t_ * hidden_dim..(t_ + 1) * hidden_dim]))
            .collect();
        println!(
            "  shard{} [{:>6},{:>6})  nonzero/token={:?}",
            i, vs, ve, nz_per_token
        );
        partials.push(part);
    }
    let b = frobenius_sum(&partials);
    println!(
        "[B] Σ embed_chunk_range over 8 shards ok in {} ms  out={}",
        t.elapsed().as_millis(),
        b.len()
    );
    finite_stats("B", &b);

    let (fail1, max1) = compare_per_token("T1", &tokens, &a, &b, hidden_dim);

    // ========================================================================
    // TEST 2 — boundary tokens: vocab_start of each shard, vocab_end-1 of each
    // ========================================================================
    println!("\n----- TEST 2: shard-boundary tokens (vstart and vend-1 of each) -----");
    let mut boundary: Vec<u32> = Vec::new();
    for (vs, ve) in SHARDS.iter() {
        boundary.push(*vs as u32);
        boundary.push((*ve - 1) as u32);
    }
    println!("  tokens: {:?}", boundary);

    let a2 = p.embed_chunk(&boundary, 0)?;
    finite_stats("A", &a2);
    let mut partials2: Vec<Vec<f32>> = Vec::with_capacity(SHARDS.len());
    for (vs, ve) in SHARDS.iter() {
        partials2.push(p.embed_chunk_range(&boundary, 0, *vs, *ve)?);
    }
    let b2 = frobenius_sum(&partials2);
    finite_stats("B", &b2);
    let (fail2, max2) = compare_per_token("T2", &boundary, &a2, &b2, hidden_dim);

    // ========================================================================
    // TEST 3 — out-of-range token: tid >= vocab_size, all shards must contribute
    // zero. We do NOT call embed_chunk(A) because it would index out of bounds;
    // we only verify B is all zero. This is the spec for "outside any shard".
    // ========================================================================
    println!("\n----- TEST 3: out-of-range token (>= vocab_size), B must be all-zero -----");
    let oob: Vec<u32> = vec![vocab_size as u32, (vocab_size + 1000) as u32];
    println!("  tokens: {:?}  (vocab_size={})", oob, vocab_size);
    let mut partials3: Vec<Vec<f32>> = Vec::with_capacity(SHARDS.len());
    for (i, (vs, ve)) in SHARDS.iter().enumerate() {
        let part = p.embed_chunk_range(&oob, 0, *vs, *ve)?;
        let nz = count_nonzero(&part);
        println!("  shard{} [{:>6},{:>6})  nonzero={}", i, vs, ve, nz);
        partials3.push(part);
    }
    let b3 = frobenius_sum(&partials3);
    let nz_total = count_nonzero(&b3);
    let pass3 = nz_total == 0;
    println!(
        "  [T3] Σ shards: nonzero={}  {}",
        nz_total,
        if pass3 { "PASS" } else { "FAIL" }
    );

    // ========================================================================
    // TEST 4 — gap tokens [last_shard_end, vocab_size). embed_chunk returns
    // a real row from the embed tensor (it's indexable by the model). The
    // cobordism merge returns zero (no shard covers them). Mismatch is a
    // CORRECTNESS BUG, not an out-of-range case like T3.
    // ========================================================================
    let last_end = SHARDS[7].1;
    let mut fail4 = false;
    let mut max4 = 0.0f32;
    if last_end < vocab_size {
        println!(
            "\n----- TEST 4: GAP tokens [{}, {}) — coverable by knot, NOT covered by cobordism shards -----",
            last_end, vocab_size
        );
        let gap_tokens: Vec<u32> = vec![last_end as u32, (vocab_size - 1) as u32];
        println!("  tokens: {:?}", gap_tokens);
        let a4 = p.embed_chunk(&gap_tokens, 0)?;
        finite_stats("A", &a4);
        let mut partials4: Vec<Vec<f32>> = Vec::with_capacity(SHARDS.len());
        for (i, (vs, ve)) in SHARDS.iter().enumerate() {
            let part = p.embed_chunk_range(&gap_tokens, 0, *vs, *ve)?;
            let nz: Vec<usize> = (0..gap_tokens.len())
                .map(|t_| count_nonzero(&part[t_ * hidden_dim..(t_ + 1) * hidden_dim]))
                .collect();
            println!("  shard{} [{:>6},{:>6})  nonzero/token={:?}", i, vs, ve, nz);
            partials4.push(part);
        }
        let b4 = frobenius_sum(&partials4);
        finite_stats("B(gap)", &b4);
        let nz_b4 = count_nonzero(&b4);
        let nz_a4 = count_nonzero(&a4);
        println!("  A nonzero={}  B nonzero={}", nz_a4, nz_b4);
        let (f4, m4) = compare_per_token("T4", &gap_tokens, &a4, &b4, hidden_dim);
        fail4 = f4;
        max4 = m4;
    } else {
        println!("\n----- TEST 4: skipped (no gap between last shard end and vocab_size) -----");
    }

    // ========================================================================
    // SUMMARY
    // ========================================================================
    println!("\n============================================================");
    let any_fail = fail1 || fail2 || !pass3 || fail4;
    let max_seen = max1.max(max2).max(max4);
    println!(" SUMMARY");
    println!(
        "   T1 (mixed shards 0/1/2/6) : {}  max-abs={:.10}",
        if !fail1 { "PASS" } else { "FAIL" },
        max1
    );
    println!(
        "   T2 (shard boundaries)     : {}  max-abs={:.10}",
        if !fail2 { "PASS" } else { "FAIL" },
        max2
    );
    println!(
        "   T3 (out-of-range -> zero) : {}",
        if pass3 { "PASS" } else { "FAIL" }
    );
    if last_end < vocab_size {
        println!(
            "   T4 (gap tokens uncovered) : {}  max-abs={:.10}",
            if !fail4 { "PASS" } else { "FAIL" },
            max4
        );
    }
    println!("   global max-abs            : {:.10}", max_seen);
    println!(
        "   verdict                   : {}",
        if !any_fail {
            "PASS — Frobenius merge bit-matches single-station embed_chunk"
        } else {
            "FAIL — cobordism merge does NOT bit-match single-station"
        }
    );
    println!("============================================================");

    if any_fail {
        std::process::exit(2);
    }
    Ok(())
}
